using ChatGPTImageOrchestrator.Application.Common.Interfaces; using ChatGPTImageOrchestrator.Domain.Entities; using ChatGPTImageOrchestrator.Domain.Enums; using ChatGPTImageOrchestrator.Domain.Interfaces;
namespace ChatGPTImageOrchestrator.Application.Services; public class AccountPoolManager(IAccountRepository accounts) : IAccountPoolManager { public Task<GeneratorAccount?> AcquireAsync(CancellationToken ct)=>accounts.GetNextActiveAsync(ct); public async Task MarkLimitReachedAsync(GeneratorAccount account, CancellationToken ct){ account.Status=AccountStatus.LimitReached; await accounts.UpdateAsync(account, ct);} }
